#include <stdio.h>
#include <math.h>

/* Reconstruct a rendered scene: gradient sky, checkered ground plane,
   and a red sphere lit by a single directional light. */
int main(void){
    int W=2400,H=1800,i,j;
    double A=4.0/3.0,Bv=1.0,camH=1.5;   /* camera at origin, plane y=-camH */
    double sy=-0.5,sz=-5.0,sr=1.0;       /* sphere center/radius */
    double Lx=1,Ly=1,Lz=-1,ln;
    ln=sqrt(Lx*Lx+Ly*Ly+Lz*Lz); Lx/=ln; Ly/=ln; Lz/=ln;
    FILE*f=fopen("reconstructed.ppm","w");
    fprintf(f,"P3\n%d %d\n255\n",W,H);
    for(j=0;j<H;j++)for(i=0;i<W;i++){
        double dx=(2.0*(i+0.5)/W-1)*A;
        double dy=(1-2.0*(j+0.5)/H)*Bv;
        double dz=-1.0, r,g,b;
        double nrm=sqrt(dx*dx+dy*dy+1), uy=dy/nrm, t=0.5*(uy+1);
        /* sky */
        r=1-0.5*t; g=1-0.3*t; b=1.0;
        /* sphere intersection (origin ray) */
        double aa=dx*dx+dy*dy+1;
        double bb=dy*(-sy)+dz*(-sz);
        double cc=sy*sy+sz*sz-sr*sr;
        double disc=bb*bb-aa*cc, ts=-1;
        if(disc>0){double s=sqrt(disc); ts=(-bb-s)/aa; if(ts<1e-4)ts=-1;}
        double tp=-1; if(dy<0){tp=-camH/dy; if(tp<1e-4)tp=-1;}
        int hitsphere = ts>0 && (tp<0||ts<tp);
        int hitplane  = tp>0 && !hitsphere;
        if(hitplane){
            double Px=tp*dx, Pz=tp*dz;
            long ix=(long)floor(Px), iz=(long)floor(Pz);
            double alb=(((ix+iz)&1)==0)?0.9:0.4;
            double sxx=Px, syy=-camH-sy, szz=Pz-sz;
            double bl=Lx*sxx+Ly*syy+Lz*szz;
            double clv=sxx*sxx+syy*syy+szz*szz-sr*sr;
            double dl=bl*bl-clv; int shadow=0;
            if(dl>0){double s=sqrt(dl); if(-bl+s>1e-4)shadow=1;}
            double shade=shadow?0.2:(0.2+0.8*Ly);
            r=g=b=alb*shade;
        }else if(hitsphere){
            double hx=ts*dx,hy=ts*dy,hz=ts*dz;
            double Nx=hx/sr,Ny=(hy-sy)/sr,Nz=(hz-sz)/sr;
            double ndl=Nx*Lx+Ny*Ly+Nz*Lz; if(ndl<0)ndl=0;
            double shade=0.2+0.8*ndl;
            r=shade; g=0.2*shade; b=0.2*shade;
        }
        int R=(int)(255.999*r),Gg=(int)(255.999*g),B=(int)(255.999*b);
        if(R>255)R=255; if(Gg>255)Gg=255; if(B>255)B=255;
        if(R<0)R=0; if(Gg<0)Gg=0; if(B<0)B=0;
        fprintf(f,"%d %d %d\n",R,Gg,B);
    }
    fclose(f);
    return 0;
}

#include <stdio.h>
#include <math.h>

/* Reconstruct a rendered scene: gradient sky, checkered ground plane,
   and a red sphere lit by a single directional light. Supersampled. */
static double A=4.0/3.0,Bv=1.0,camH=1.5;
static double sy=-0.5,sz=-5.0,sr=1.0;
static double Lx,Ly,Lz;

static void shade(double dx,double dy,double*rgb){
    double dz=-1.0,r,g,b;
    double nrm=sqrt(dx*dx+dy*dy+1), uy=dy/nrm, t=0.5*(uy+1);
    r=1-0.5*t; g=1-0.3*t; b=1.0;                 /* sky */
    double aa=dx*dx+dy*dy+1;
    double bb=dy*(-sy)+dz*(-sz);
    double cc=sy*sy+sz*sz-sr*sr;
    double disc=bb*bb-aa*cc, ts=-1;
    if(disc>0){double s=sqrt(disc); ts=(-bb-s)/aa; if(ts<1e-4)ts=-1;}
    double tp=-1; if(dy<0){tp=-camH/dy; if(tp<1e-4)tp=-1;}
    int hitsphere = ts>0 && (tp<0||ts<tp);
    int hitplane  = tp>0 && !hitsphere;
    if(hitplane){
        double Px=tp*dx, Pz=tp*dz;
        long ix=(long)floor(Px), iz=(long)floor(Pz);
        double alb=(((ix+iz)&1)==0)?0.9:0.4;
        double sxx=Px, syy=-camH-sy, szz=Pz-sz;
        double bl=Lx*sxx+Ly*syy+Lz*szz;
        double clv=sxx*sxx+syy*syy+szz*szz-sr*sr;
        double dl=bl*bl-clv; int shadow=0;
        if(dl>0){double s=sqrt(dl); if(-bl+s>1e-4)shadow=1;}
        double sh=shadow?0.2:(0.2+0.8*Ly);
        r=g=b=alb*sh;
    }else if(hitsphere){
        double hx=ts*dx,hy=ts*dy,hz=ts*dz;
        double Nx=hx/sr,Ny=(hy-sy)/sr,Nz=(hz-sz)/sr;
        double ndl=Nx*Lx+Ny*Ly+Nz*Lz; if(ndl<0)ndl=0;
        double sh=0.2+0.8*ndl;
        r=sh; g=0.2*sh; b=0.2*sh;
    }
    rgb[0]+=r; rgb[1]+=g; rgb[2]+=b;
}

int main(void){
    int W=2400,H=1800,i,j,sx,sv,SS=4;
    double ln=sqrt(3.0); Lx=1/ln; Ly=1/ln; Lz=-1/ln;
    FILE*f=fopen("reconstructed.ppm","w");
    fprintf(f,"P3\n%d %d\n255\n",W,H);
    for(j=0;j<H;j++)for(i=0;i<W;i++){
        double rgb[3]={0,0,0};
        for(sv=0;sv<SS;sv++)for(sx=0;sx<SS;sx++){
            double px=i+(sx+0.5)/SS, py=j+(sv+0.5)/SS;
            double dx=(2.0*px/W-1)*A;
            double dy=(1-2.0*py/H)*Bv;
            shade(dx,dy,rgb);
        }
        double n=SS*SS;
        int R=(int)(255.999*rgb[0]/n),G=(int)(255.999*rgb[1]/n),B=(int)(255.999*rgb[2]/n);
        if(R>255)R=255; if(G>255)G=255; if(B>255)B=255;
        if(R<0)R=0; if(G<0)G=0; if(B<0)B=0;
        fprintf(f,"%d %d %d\n",R,G,B);
    }
    fclose(f);
    return 0;
}

